SELECT ,
IFNULL(su.account_status,'1') account_status

FROM app_user su

where 1 = 1
  and su.id = #{id}  
  and su.username = #{username}  
  and su.password = #{password}  
  and su.nickname = #{nickname}  
  and su.sex = #{sex}  
  and su.phone = #{phone}  
  and su.h_img = #{h_img}  
  and su.account_status = #{account_status}

